// --- GLOBAL ERROR LISTENERS FOR ROBUST DEBUGGING ---
window.onerror = function(message, source, lineno, colno, error) {
  const errMsg = "GLOBAL ERROR:\n" + message + "\nSource: " + source + "\nLine: " + lineno + "\nCol: " + colno + "\nStack: " + (error ? error.stack : "no stack");
  alert(errMsg);
  console.error("GLOBAL ERROR:", message, error);
};
window.addEventListener("unhandledrejection", function(event) {
  const errMsg = "UNHANDLED REJECTION:\n" + event.reason + "\nStack: " + (event.reason ? event.reason.stack : "no stack");
  alert(errMsg);
});


function getTotalLevel(char) {
  let lvl = parseInt(char.level) || 1;
  if (char.multiclasses && char.multiclasses.length > 0) {
    char.multiclasses.forEach(mc => { lvl += (parseInt(mc.level) || 1); });
  }
  return lvl;
}
window.getTotalLevel = getTotalLevel;

function getAllClasses(char) {
  const classes = [{ class: char.class, subclass: char.subclass, level: char.level }];
  if (char.multiclasses && char.multiclasses.length > 0) {
    classes.push(...char.multiclasses);
  }
  return classes;
}
window.getAllClasses = getAllClasses;

