// Condiciones
const CONDITIONS_DB_ES = {
  "Apresado": "Velocidad 0. Ataques contra ti tienen ventaja. Tus ataques tienen desventaja.",
  "Asustado": "Desventaja en pruebas y ataques mientras veas a la fuente del miedo. No puedes acercarte voluntariamente.",
  "Aturdido": "Incapacitado. Fallas salvaciones de FUE y DES automáticamente. Ataques contra ti tienen ventaja.",
  "Cegado": "Fallas pruebas de vista. Ataques contra ti tienen ventaja. Tus ataques tienen desventaja.",
  "Derribado": "Solo puedes arrastrarte. Ataques contra ti a 5 pies tienen ventaja (desventaja si están más lejos). Desventaja en tus ataques.",
  "Desventaja": "Tiras 2d20 y te quedas con el menor en tu próxima tirada.",
  "Encantado": "No puedes atacar al encantador. El encantador tiene ventaja en interacciones sociales.",
  "Envenenado": "Desventaja en tiradas de ataque y pruebas de característica.",
  "Exhausto": "Cada nivel resta 1 a tus d20 y a la CD de tus conjuros. A nivel 6 mueres.",
  "Incapacitado": "No puedes realizar Acciones ni Reacciones. Pierdes la Concentración.",
  "Inconsciente": "Incapacitado y Derribado. Fallas salvaciones FUE/DES. Ataques a 5 pies son Críticos.",
  "Invisible": "No puedes ser visto. Tus ataques tienen ventaja. Ataques contra ti tienen desventaja.",
  "Paralizado": "Incapacitado. Fallas salvaciones de FUE y DES. Ataques a 5 pies son Críticos.",
  "Petrificado": "Transformado en piedra. Incapacitado, resistencia a todo el daño. Falla salvaciones FUE/DES.",
  "Retenido": "Velocidad 0. Ataques contra ti tienen ventaja. Tus ataques y salvaciones DES tienen desventaja.",
  "Sordo": "Fallas automáticamente cualquier prueba que requiera oír.",
  "Ventaja": "Tiras 2d20 y te quedas con el mayor en tu próxima tirada."
};
let CONDITIONS_DB = CONDITIONS_DB_ES;

function populateConditionsModal() {
  const grid = document.getElementById("conditionsGridSelect");
  if (!grid) return;
  grid.innerHTML = "";
  Object.keys(CONDITIONS_DB).forEach(cond => {
    const id = "cond-" + cond.toLowerCase().replace(/\s+/g, '-');
    grid.innerHTML += `
      <div class="condition-option" style="display:flex; flex-direction:column; align-items:flex-start; margin-bottom:12px; width:100%;">
        <div style="display:flex; align-items:center;">
          <input type="checkbox" id="${id}" value="${cond}">
          <label for="${id}" style="margin-left:6px; font-weight:bold; color:var(--gold); cursor:pointer;">${cond}</label>
        </div>
        <div style="font-size:11px; color:var(--text-dim); margin-left:24px; margin-top:4px; line-height:1.2; font-style:italic;">
          ${CONDITIONS_DB[cond]}
        </div>
      </div>
    `;
  });
}

function openConditionsModal() {
  const char = getActiveCharacter();
  if (!char) return;

  populateConditionsModal();

  const activeConditions = char.conditions || [];
  
  document.querySelectorAll("#conditionsModal input[type='checkbox']").forEach(cb => {
    cb.checked = activeConditions.includes(cb.value);
  });

  document.getElementById("conditionsModal").classList.add("active");
}

function closeConditionsModal() {
  document.getElementById("conditionsModal").classList.remove("active");
}

function saveConditionsSubmit() {
  const char = getActiveCharacter();
  if (!char) return;

  const newConditions = [];
  document.querySelectorAll("#conditionsModal input[type='checkbox']:checked").forEach(cb => {
    newConditions.push(cb.value);
  });

  char.conditions = newConditions;
  saveData();
  renderConditions(char);
  closeConditionsModal();
}

function removeConditionDirectly(conditionName) {
  const char = getActiveCharacter();
  if (!char) return;

  char.conditions = (char.conditions || []).filter(c => c !== conditionName);
  saveData();
  renderConditions(char);
}

function renderConditions(char) {
  const listEl = document.getElementById("activeConditionsList");
  if (!listEl) return;

  listEl.innerHTML = "";
  
  const conditions = char.conditions || [];

  if (conditions.length === 0) {
    listEl.innerHTML = "";
    return;
  }

  conditions.forEach(cond => {
    const badge = document.createElement("span");
    badge.className = `condition-badge ${cond.toLowerCase().replace(/\s+/g, '-')}`;
    badge.innerHTML = `${cond} <span class="remove-cond-btn" onclick="removeConditionDirectly('${cond}')">&times;</span>`;
    listEl.appendChild(badge);
  });
}

// Salvaciones de Muerte
function toggleDeathSave(type, num) {
  const char = getActiveCharacter();
  if (!char) return;

  if (!char.deathSaves) {
    char.deathSaves = { successes: 0, failures: 0 };
  }

  if (type === 'success') {
    const cb = document.getElementById(`dsSuccess${num}`);
    if (cb.checked) {
      char.deathSaves.successes = Math.max(char.deathSaves.successes, num);
    } else {
      char.deathSaves.successes = Math.min(char.deathSaves.successes, num - 1);
    }
  } else if (type === 'failure') {
    const cb = document.getElementById(`dsFail${num}`);
    if (cb.checked) {
      char.deathSaves.failures = Math.max(char.deathSaves.failures, num);
    } else {
      char.deathSaves.failures = Math.min(char.deathSaves.failures, num - 1);
    }
  }

  saveData();
  renderDeathSaves(char);
}

function renderDeathSaves(char) {
  const ds = char.deathSaves || { successes: 0, failures: 0 };
  
  for (let i = 1; i <= 3; i++) {
    const sCb = document.getElementById(`dsSuccess${i}`);
    if (sCb) sCb.checked = i <= ds.successes;

    const fCb = document.getElementById(`dsFail${i}`);
    if (fCb) fCb.checked = i <= ds.failures;
  }

  const statusText = document.getElementById("deathStatusText");
  if (statusText) {
    if (ds.successes >= 3) {
      statusText.textContent = "¡ESTABILIZADO! (Recupera PV para despertar)";
      statusText.className = "death-status-text stabilized";
    } else if (ds.failures >= 3) {
      statusText.textContent = "FALLECIDO 💀 (Haz clic en Curar para resucitar)";
      statusText.className = "death-status-text deceased";
    } else {
      statusText.textContent = "Tira salvaciones al inicio de tu turno";
      statusText.className = "death-status-text";
    }
  }
}

// --- SUBCLASES Y SISTEMA DE SUBIDA DE NIVEL ---

function updateSubclassDropdown(classVal, selectId, currentVal) {
  const select = document.getElementById(selectId);
  if (!select) return;

  select.innerHTML = "";
  const list = SUBCLASSES_DB[classVal] || [];

  list.forEach(sub => {
    const opt = document.createElement("option");
    opt.value = sub;
    opt.textContent = translateVal(sub);
    if (sub === currentVal) opt.selected = true;
    select.appendChild(opt);
  });
}

function setupSubclassResources(char) {
  const lvl = char.level || 1;
  const sub = (char.subclass || "").trim().toLowerCase();
  const cls = (char.class || "").trim().toLowerCase();

  const oldSubCurrent = char.subclassResource ? char.subclassResource.current : undefined;
  const oldPortentDice = char.subclassResource ? char.subclassResource.portentDice : [];
  char.subclassResource = {
    name: "",
    desc: "",
    current: 0,
    max: 0,
    type: "none",
    portentDice: oldPortentDice || []
  };

  const isWarrior = cls === "guerrero" || cls === "fighter";
  const isWizard = cls === "mago" || cls === "wizard";
  const isRogue = cls === "pícaro" || cls === "rogue" || cls === "picaro";
  const isSorcerer = cls === "hechicero" || cls === "sorcerer";
  const isDruid = cls === "druida" || cls === "druid";
  const isWarlock = cls === "brujo" || cls === "warlock";
  const isPaladin = cls === "paladín" || cls === "paladin";
  const isRanger = cls === "explorador" || cls === "ranger";

  if (isWarrior && (sub === "maestro de batalla" || sub === "battle master")) {
    char.subclassResource.name = "Dados de Superioridad (d8)";
    char.subclassResource.desc = "Gástalos en Maniobras tácticas. Se recuperan en Descanso Corto.";
    let max = 4;
    if (lvl >= 15) max = 6;
    else if (lvl >= 7) max = 5;
    char.subclassResource.max = max;
    char.subclassResource.type = "bubbles";
  } else if (isWarrior && (sub === "caballero psiónico" || sub === "psi warrior" || sub === "caballero psionico")) {
    char.subclassResource.name = "Dados de Energía Psiónica";
    char.subclassResource.desc = "Dados para tus talentos y golpes psiónicos. Se recuperan en Descanso Largo.";
    char.subclassResource.max = char.profBonus * 2;
    char.subclassResource.type = "bubbles";
  } else if (isRogue && (sub === "cuchilla del alma" || sub === "soulknife")) {
    char.subclassResource.name = "Dados de Energía Psiónica";
    char.subclassResource.desc = "Dados para tus talentos y hojas psíquicas. Se recuperan en Descanso Largo.";
    char.subclassResource.max = char.profBonus * 2;
    char.subclassResource.type = "bubbles";
  } else if (isWizard && (sub === "adivinación" || sub === "divination" || sub === "adivinacion")) {
    char.subclassResource.name = "Dados de Presagio (Portent)";
    char.subclassResource.desc = "Dados pre-tirados para sustituir cualquier tirada. Se recuperan en Descanso Largo.";
    const count = lvl >= 14 ? 3 : 2;
    char.subclassResource.max = count;
    char.subclassResource.type = "portent";
    
    if (!char.subclassResource.portentDice || char.subclassResource.portentDice.length !== count) {
      char.subclassResource.portentDice = Array.from({ length: count }, () => ({
        val: Math.floor(Math.random() * 20) + 1,
        used: false
      }));
    }
  } else if (isWarlock && sub === "celestial") {
    char.subclassResource.name = "Luz Curativa (d6)";
    char.subclassResource.desc = "Acción Bonus: cúrate a ti o a un aliado a 60 pies. Se recupera en Descanso Largo.";
    char.subclassResource.max = lvl + 1;
    char.subclassResource.type = "numeric";
  } else if (isWarlock && (sub === "archihada" || sub === "archfey")) {
    char.subclassResource.name = "Pasos de las Hadas";
    char.subclassResource.desc = "Acción Bonus: teletranspórtate 30 pies (como Paso Brumoso) con efectos adicionales. Se recupera en Descanso Largo.";
    const chaMod = calcModifier(getEffectiveAttributes(char).cha);
    char.subclassResource.max = Math.max(1, chaMod);
    char.subclassResource.type = "bubbles";
  } else if (isSorcerer && (sub === "magia salvaje" || sub === "wild magic")) {
    char.subclassResource.name = "Marea de Caos";
    char.subclassResource.desc = "Obtén ventaja en una tirada. Induce Oleada de Magia Salvaje. Se recupera en Descanso Largo.";
    char.subclassResource.max = 1;
    char.subclassResource.type = "bubbles";
  } else if (isDruid && (sub === "luna" || sub === "moon")) {
    if (lvl >= 6) {
      char.subclassResource.name = "Paso de Luz Lunar";
      char.subclassResource.desc = "Acción Bonus: teletranspórtate 30 pies y cura 1d10. Se recupera en Descanso Largo.";
      const wisMod = calcModifier(getEffectiveAttributes(char).wis);
      char.subclassResource.max = Math.max(1, wisMod);
      char.subclassResource.type = "bubbles";
    }
  } else if (isDruid && (sub === "estrellas" || sub === "stars")) {
    char.subclassResource.name = "Saeta Guía Gratuita";
    char.subclassResource.desc = "Lanza Saeta Guía (nivel 1) sin gastar ranura de conjuro. Se recupera en Descanso Largo.";
    char.subclassResource.max = char.profBonus;
    char.subclassResource.type = "bubbles";
  } else if (isPaladin && sub && sub !== "") {
    if (lvl >= 3) {
      char.subclassResource.name = "Canalizar Divinidad";
      char.subclassResource.desc = "Usa el poder sagrado de tu juramento (ej. Arma Sagrada, Envidia Pavorosa). Se recupera en Descanso Corto.";
      char.subclassResource.max = 2;
      char.subclassResource.type = "bubbles";
    }
  } else if (isRanger && (sub === "acechador de la sombra" || sub === "gloom stalker")) {
    char.subclassResource.name = "Emboscador Pavoroso";
    char.subclassResource.desc = "Agrega 2d6 de daño a un ataque o asusta a un enemigo al impactar. Se recupera en Descanso Largo.";
    const wisMod = calcModifier(getEffectiveAttributes(char).wis);
    char.subclassResource.max = Math.max(1, wisMod);
    char.subclassResource.type = "bubbles";
  }

  // Preservar el current si ya existía y es válido, sino empezar lleno
  if (oldSubCurrent !== undefined && oldSubCurrent <= char.subclassResource.max) {
    char.subclassResource.current = oldSubCurrent;
  } else {
    char.subclassResource.current = char.subclassResource.max;
  }
  setupAllResources(char);
}

function renderSubclassResources(char) {
  renderAllResources(char);
}

function toggleSubclassResourceBubble(index) {
  const char = getActiveCharacter();
  if (!char || !char.subclassResource) return;

  const res = char.subclassResource;
  const currentVal = res.current;
  let newVal = index + 1;

  if (currentVal === newVal) {
    newVal = index;
  }

  res.current = newVal;
  if (char.resourceCharges) {
    char.resourceCharges[res.name] = newVal;
  }
  saveData();
  renderAllResources(char);
}

function togglePortentDice(idx) {
  const char = getActiveCharacter();
  if (!char || !char.subclassResource || !char.subclassResource.portentDice) return;

  const dice = char.subclassResource.portentDice[idx];
  if (dice) {
    dice.used = !dice.used;
    char.subclassResource.current = char.subclassResource.portentDice.filter(d => !d.used).length;
    if (char.resourceCharges) {
      char.resourceCharges[char.subclassResource.name] = char.subclassResource.current;
    }
    saveData();
    renderAllResources(char);
  }
}



// --- SISTEMA DE SUBIDA DE NIVEL ---

function promptSubclassSelection(char, className, currentSubclass) {
  const list = SUBCLASSES_DB[className] || [];
  if (list.length === 0) return currentSubclass || "";

  let msg = `¡Tu clase ${className} ha alcanzado el Nivel 3! Elige tu Subclase:\n\n`;
  list.forEach((sub, idx) => {
    msg += `${idx + 1}. ${translateVal(sub)}\n`;
  });
  if (currentSubclass) {
    msg += `\nSubclase actual: ${translateVal(currentSubclass)} (deja en blanco o cancela para mantenerla)`;
  }
  msg += `\nEscribe el número de tu elección (1-${list.length}):`;

  const choiceStr = prompt(msg, "1");
  if (choiceStr === null || choiceStr.trim() === "") {
    return currentSubclass || list[0] || "";
  }

  const choice = parseInt(choiceStr);
  if (isNaN(choice) || choice < 1 || choice > list.length) {
    alert("Opción no válida. Se mantendrá la subclase por defecto.");
    return currentSubclass || list[0] || "";
  }

  return list[choice - 1];
}

function triggerLevelUp() {
  const char = getActiveCharacter();
  if (!char) return;

  const currentTotalLvl = getTotalLevel(char);
  if (currentTotalLvl >= 20) {
    alert("¡Tu héroe ya está al nivel máximo (20)!");
    return;
  }

  // 1. Preguntar qué clase deseas subir de nivel
  let optionsText = `¡SUBIDA DE NIVEL! (Nivel Total actual: ${currentTotalLvl})\n\n`;
  optionsText += `Elige qué clase deseas subir de nivel:\n`;
  optionsText += `1. ${char.class} (Clase Principal, Nivel: ${char.level} -> ${char.level + 1})\n`;
  
  const multiclasses = char.multiclasses || [];
  multiclasses.forEach((mc, index) => {
    optionsText += `${index + 2}. ${mc.class} (Multiclase, Nivel: ${mc.level} -> ${mc.level + 1})\n`;
  });
  
  const newMcOptionIndex = multiclasses.length + 2;
  optionsText += `${newMcOptionIndex}. Añadir una nueva multiclase (Nivel 1)\n\n`;
  optionsText += `Escribe el número de tu elección (1-${newMcOptionIndex}):`;

  const choiceStr = prompt(optionsText, "1");
  if (choiceStr === null) return; // Cancelar

  const choice = parseInt(choiceStr);
  if (isNaN(choice) || choice < 1 || choice > newMcOptionIndex) {
    alert("Opción no válida. Cancelando subida de nivel.");
    return;
  }

  let classLeveledUp = "";
  let isNewMulticlass = false;
  let chosenMcIndex = -1;

  if (choice === 1) {
    classLeveledUp = char.class;
  } else if (choice === newMcOptionIndex) {
    isNewMulticlass = true;
    const availableClasses = ["Guerrero", "Mago", "Clérigo", "Pícaro", "Bardo", "Druida", "Bárbaro", "Hechicero", "Brujo", "Paladín", "Explorador", "Monje"];
    let classPromptText = "Selecciona la nueva clase para multiclase:\n";
    availableClasses.forEach((c, idx) => {
      classPromptText += `${idx + 1}. ${c}\n`;
    });
    classPromptText += "\nEscribe el número o el nombre de la clase:";
    const newClassInput = prompt(classPromptText, "1");
    if (newClassInput === null) return;

    let newClassName = newClassInput.trim();
    const parsedIdx = parseInt(newClassName);
    if (!isNaN(parsedIdx) && parsedIdx >= 1 && parsedIdx <= availableClasses.length) {
      newClassName = availableClasses[parsedIdx - 1];
    } else {
      const found = availableClasses.find(c => c.toLowerCase() === newClassName.toLowerCase());
      if (found) {
        newClassName = found;
      } else {
        alert("Clase no válida. Cancelando subida de nivel.");
        return;
      }
    }

    if (newClassName.toLowerCase() === char.class.toLowerCase()) {
      alert(`Tu clase principal ya es ${char.class}. Selecciona otra clase.`);
      return;
    }
    const alreadyExists = multiclasses.some(mc => mc.class.toLowerCase() === newClassName.toLowerCase());
    if (alreadyExists) {
      alert(`Ya tienes la multiclase ${newClassName}. Elige subir esa clase en el menú anterior.`);
      return;
    }

    classLeveledUp = newClassName;
  } else {
    chosenMcIndex = choice - 2;
    classLeveledUp = multiclasses[chosenMcIndex].class;
  }

  // Determinar el dado de golpe para la clase elegida
  let hpDieSides = 8;
  switch (classLeveledUp) {
    case "Bárbaro": hpDieSides = 12; break;
    case "Guerrero":
    case "Paladín":
    case "Explorador":
      hpDieSides = 10;
      break;
    case "Mago":
    case "Hechicero":
      hpDieSides = 6;
      break;
    default:
      hpDieSides = 8;
      break;
  }
  const classHitDiceType = `d${hpDieSides}`;
  const conMod = calcModifier(getEffectiveAttributes(char).con);
  const averageRoll = Math.floor(hpDieSides / 2) + 1;
  const conModStr = conMod >= 0 ? `+${conMod}` : `${conMod}`;
  
  let hpGain = 0;
  let summaryDetails = "";
  let skipPrompt = false;

  const nextTotalLvl = currentTotalLvl + 1;

  if (char.autoHP !== false) {
    skipPrompt = true;
    hpGain = Math.max(1, averageRoll + conMod);
    summaryDetails = `Cálculo Automático (${classLeveledUp}): obtuviste ${averageRoll} (Media) ${conModStr} (CON) = +${hpGain} PV Máximos.`;
  } else {
    const method = prompt(
      `¡SUBIDA DE NIVEL! ${char.name} subirá al Nivel Total ${nextTotalLvl} (${classLeveledUp}).\n\n` +
      `Elige el método para incrementar tus PV Máximos:\n` +
      `1. Tirar el Dado (${classHitDiceType} ${conModStr})\n` +
      `2. Tomar la Media Fija (${averageRoll} ${conModStr})\n\n` +
      `Escribe '1' o '2':`, "2"
    );

    if (method === null) return; // Cancelar

    if (method === "1") {
      const roll = Math.floor(Math.random() * hpDieSides) + 1;
      hpGain = Math.max(1, roll + conMod);
      summaryDetails = `Tirada de Dado: obtuviste un ${roll} ${conModStr} (Constitución) = +${hpGain} PV Máximos.`;
    } else if (method === "2" || method === "") {
      hpGain = Math.max(1, averageRoll + conMod);
      summaryDetails = `Media Fija: obtuviste ${averageRoll} ${conModStr} (Constitución) = +${hpGain} PV Máximos.`;
    } else {
      alert("Opción no válida. Cancelando subida de nivel.");
      return;
    }
  }

  // Aplicar el incremento de nivel en el modelo
  let leveledClassLevel = 1;
  if (choice === 1) {
    char.level += 1;
    leveledClassLevel = char.level;
  } else if (isNewMulticlass) {
    if (!char.multiclasses) char.multiclasses = [];
    char.multiclasses.push({
      class: classLeveledUp,
      subclass: "",
      level: 1
    });
    leveledClassLevel = 1;
  } else {
    char.multiclasses[chosenMcIndex].level += 1;
    leveledClassLevel = char.multiclasses[chosenMcIndex].level;
  }

  // Si la clase que sube llega a nivel >= 3, elegir subclase
  if (leveledClassLevel >= 3) {
    if (choice === 1) {
      if (!char.subclass || char.subclass === "" || leveledClassLevel === 3) {
        char.subclass = promptSubclassSelection(char, char.class, char.subclass);
      }
    } else if (!isNewMulticlass) {
      const mc = char.multiclasses[chosenMcIndex];
      if (!mc.subclass || mc.subclass === "" || leveledClassLevel === 3) {
        mc.subclass = promptSubclassSelection(char, classLeveledUp, mc.subclass);
      }
    }
  }

  // Recalcular puntos de vida máximos y actuales
  if (char.autoHP !== false) {
    const oldHPMax = char.hpMax;
    char.hpMax = calculateMaxHP(char);
    char.hpCurrent += (char.hpMax - oldHPMax);
  } else {
    char.hpMax += hpGain;
    char.hpCurrent += hpGain;
    
    // Bonificaciones manuales según nivel total
    const totalLvl = getTotalLevel(char);
    if (char.race === "Enano") {
      char.hpMax += 1;
      char.hpCurrent += 1;
      summaryDetails += ` (+1 PV por Especie Enana)`;
    }
    if (char.background === "Granjero") {
      char.hpMax += 2;
      char.hpCurrent += 2;
      summaryDetails += ` (+2 PV por Dote Duro de Granjero)`;
    }
    if (char.feats && char.feats.some(f => f && f.name && (f.name.includes("Duro") || f.name.includes("Tough")))) {
      if (char.background !== "Granjero") {
        char.hpMax += 2;
        char.hpCurrent += 2;
        summaryDetails += ` (+2 PV por Dote Duro)`;
      }
    }
  }

  // Recalcular competencia basada en nivel total
  char.profBonus = Math.floor((getTotalLevel(char) - 1) / 4) + 2;

  // Recalcular slots y recursos
  setupDefaultSpellSlots(char);
  setupClassResources(char);
  setupSubclassResources(char);

  if (char.autoAC !== false) {
    char.ac = calculateAC(char);
  }

  saveData();
  renderActiveCharacter();
  renderCharacterList();

  alert(
    `¡FELICIDADES! ${char.name} ha alcanzado el Nivel Total ${getTotalLevel(char)}.\n` +
    `Ahora tiene nivel ${choice === 1 ? char.level : (isNewMulticlass ? 1 : char.multiclasses[chosenMcIndex].level)} en ${classLeveledUp}.\n\n` +
    `- ${summaryDetails}\n` +
    `- Nuevos PV Máximos: ${char.hpMax}\n` +
    `- Dados de Golpe y recursos de clase/subclase re-escalados al nuevo nivel.\n` +
    `- Ranuras de Hechizos actualizadas.`
  );
}

// --- RASGOS DE ORIGEN Y EDICIÓN MANUAL AUXILIARES ---

function updateBackgroundAsiOptions() {
  const bgVal = document.getElementById("newCharBg")?.value;
  const p2Select = document.getElementById("newCharAsiPlus2");
  const p1Select = document.getElementById("newCharAsiPlus1");
  const featText = document.getElementById("newCharFeatDesc");

  if (!bgVal || !p2Select || !p1Select || !featText) return;

  const bgData = BACKGROUNDS_DB[bgVal];
  if (!bgData) return;

  const statsNames = {
    str: "Fuerza (FUE)",
    dex: "Destreza (DES)",
    con: "Constitución (CON)",
    int: "Inteligencia (INT)",
    wis: "Sabiduría (SAB)",
    cha: "Carisma (CAR)"
  };

  const prevP2 = p2Select.value;
  const prevP1 = p1Select.value;

  p2Select.innerHTML = "";
  bgData.stats.forEach(st => {
    const opt = document.createElement("option");
    opt.value = st;
    opt.textContent = statsNames[st];
    p2Select.appendChild(opt);
  });

  if (bgData.stats.includes(prevP2)) {
    p2Select.value = prevP2;
  }

  const updateP1 = () => {
    const selectedP2 = p2Select.value;
    p1Select.innerHTML = "";
    bgData.stats.forEach(st => {
      if (st !== selectedP2) {
        const opt = document.createElement("option");
        opt.value = st;
        opt.textContent = statsNames[st];
        p1Select.appendChild(opt);
      }
    });
    if (bgData.stats.includes(prevP1) && prevP1 !== selectedP2) {
      p1Select.value = prevP1;
    }
  };

  p2Select.onchange = updateP1;
  updateP1();

  const bgInfoContainer = document.getElementById("newCharBgInfoContainer");
  const bgDesc = document.getElementById("newCharBgDesc");
  if (bgInfoContainer && bgDesc) {
    bgInfoContainer.style.display = "block";
    bgDesc.innerHTML = bgData.desc || "";
  }

  featText.innerHTML = `<strong>Dote de Origen (Lvl 1):</strong> ${bgData.feat}<br><span style="font-size:10px;color:var(--text-muted);line-height:1.2;display:block;margin-top:2px;">${bgData.featDesc}</span>`;
}

function switchEditTab(tabId) {
  // Ocultar todos los contenidos
  document.querySelectorAll('.edit-tab-content').forEach(el => {
    el.classList.remove('active');
  });
  // Quitar active de todos los botones
  document.querySelectorAll('.edit-tab-btn').forEach(btn => {
    btn.classList.remove('active');
  });

  // Activar el contenido seleccionado
  const target = document.getElementById(tabId);
  if (target) target.classList.add('active');

  // Buscar el botón correspondiente y activarlo
  const btn = document.querySelector(`.edit-tab-btn[data-tab="${tabId}"], .edit-tab-btn[onclick="switchEditTab('${tabId}')"]`);
  if (btn) btn.classList.add('active');
}

function renderOriginTraits(char) {
  const card = document.getElementById("originTraitsCard");
  const list = document.getElementById("originTraitsList");
  if (!card || !list) return;

  const speciesData = SPECIES_DB[char.race];
  const bgData = BACKGROUNDS_DB[char.background];
  
  const classes = window.getAllClasses ? window.getAllClasses(char) : [{class: char.class, subclass: char.subclass, level: char.level}];
  let subclassTraits = [];
  if (window.SUBCLASS_TRAITS_DB) {
    classes.forEach(cls => {
      if (cls.subclass && window.SUBCLASS_TRAITS_DB[cls.subclass]) {
        const traitsForLvl = window.SUBCLASS_TRAITS_DB[cls.subclass].filter(t => t.level <= (parseInt(cls.level)||1));
        traitsForLvl.forEach(t => {
          t.className = cls.class;
        });
        subclassTraits = subclassTraits.concat(traitsForLvl);
      }
    });
  }

  const hasCustomTraits = char.customOriginTraits && char.customOriginTraits.length > 0;

  if (!speciesData && !bgData && (subclassTraits.length === 0) && !hasCustomTraits) {
    card.style.display = "none";
    card.dataset.empty = "true";
    list.innerHTML = "";
    return;
  }

  card.style.display = "block";
  card.dataset.empty = "false";
  let html = "";

  // 1. RASGOS DE ESPECIE
  if (speciesData) {
    html += `<h3 style="font-size:12px;color:var(--gold-bright);margin-bottom:8px;text-transform:uppercase;border-bottom:1px dashed var(--gold-dark);padding-bottom:2px;letter-spacing:0.05em;">Especie: ${char.race} (Vel: ${speciesData.speed}p | Visión: ${speciesData.vision})</h3>`;
    (speciesData.traits || []).forEach(tr => {
      if (!tr || !tr.name) return;
      html += `
        <div class="trait-item" style="margin-bottom:8px;">
          <div class="trait-name" style="font-weight:600;font-size:12px;color:var(--gold);">${tr.name}</div>
          <div class="trait-desc" style="font-size:11px;color:var(--text-dim);margin-top:2px;line-height:1.3;">${tr.desc || ""}</div>
        </div>
      `;
    });
  }

  // 1.5. RASGOS DE LINAJE / SUBESPECIE
  if (speciesData && char.subrace && speciesData.lineages && speciesData.lineages[char.subrace]) {
    const linTraits = speciesData.lineages[char.subrace];
    linTraits.forEach(tr => {
      if (!tr || !tr.name) return;
      html += `
        <div class="trait-item" style="margin-bottom:8px;">
          <div class="trait-name" style="font-weight:600;font-size:12px;color:var(--gold);">${tr.name}</div>
          <div class="trait-desc" style="font-size:11px;color:var(--text-dim);margin-top:2px;line-height:1.3;">${tr.desc || ""}</div>
        </div>
      `;
    });
  }

  // 2. RASGOS DE TRASFONDO
  if (bgData) {
    html += `<h3 style="font-size:12px;color:var(--gold-bright);margin-top:14px;margin-bottom:8px;text-transform:uppercase;border-bottom:1px dashed var(--gold-dark);padding-bottom:2px;letter-spacing:0.05em;">Trasfondo: ${char.background}</h3>`;
    html += `
      <div class="trait-item" style="margin-bottom:8px;">
        <div class="trait-name" style="font-weight:600;font-size:12px;color:var(--gold);">Dote de Origen: ${bgData.feat || ""}</div>
        <div class="trait-desc" style="font-size:11px;color:var(--text-dim);margin-top:2px;line-height:1.3;">${bgData.featDesc || ""}</div>
      </div>
    `;
  }

  
    // 3. RASGOS DE SUBCLASE (Multiclase)
    if (subclassTraits && subclassTraits.length > 0) {
      html += `<h3 style="font-size:12px;color:var(--gold-bright);margin-top:14px;margin-bottom:8px;text-transform:uppercase;border-bottom:1px dashed var(--gold-dark);padding-bottom:2px;letter-spacing:0.05em;">Rasgos de Clase/Subclase</h3>`;
      subclassTraits.forEach(tr => {
        if (!tr || !tr.name) return;
        html += `
          <div class="trait-item" style="margin-bottom:8px;">
            <div class="trait-name" style="font-weight:600;font-size:12px;color:var(--gold);">${tr.name} <span style="font-size:10px;color:var(--text-dim);">(${tr.className || ""})</span></div>
            <div class="trait-desc" style="font-size:11px;color:var(--text-dim);margin-top:2px;line-height:1.3;">${tr.desc || ""}</div>
          </div>
        `;
      });
    }

  // 4. RASGOS DE ORIGEN PERSONALIZADOS
  if (hasCustomTraits) {
    const lang = localStorage.getItem("dnd55_language") || "es";
    const customTitle = lang === "en" ? "Custom Origin Features" : "Rasgos de Origen Personalizados";
    html += `<h3 style="font-size:12px;color:var(--gold-bright);margin-top:14px;margin-bottom:8px;text-transform:uppercase;border-bottom:1px dashed var(--gold-dark);padding-bottom:2px;letter-spacing:0.05em;">${customTitle}</h3>`;
    char.customOriginTraits.forEach((tr, index) => {
      if (!tr || !tr.name) return;
      html += `
        <div class="trait-item" style="margin-bottom:8px; position:relative; padding-right:30px;">
          <div style="display:flex; justify-content:space-between; align-items:center;">
            <div class="trait-name" style="font-weight:600;font-size:12px;color:var(--gold);">${tr.name}</div>
            <button class="action-btn" onclick="removeCustomOriginTrait(${index})" style="width:20px; height:20px; min-height:20px; padding:0; position:absolute; right:0; top:0;">
              <svg viewBox="0 0 24 24" style="width:12px; height:12px; fill:var(--error);"><path d="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z"/></svg>
            </button>
          </div>
          <div class="trait-desc" style="font-size:11px;color:var(--text-dim);margin-top:2px;line-height:1.3;">${tr.desc || ""}</div>
        </div>
      `;
    });
  }

  list.innerHTML = html;
}

function openAddOriginTraitModal() {
  const modal = document.getElementById("addOriginTraitModal");
  if (!modal) return;
  document.getElementById("originTraitName").value = "";
  document.getElementById("originTraitDesc").value = "";
  modal.classList.add("active");
}

function closeAddOriginTraitModal() {
  const modal = document.getElementById("addOriginTraitModal");
  if (modal) modal.classList.remove("active");
}

function addOriginTrait() {
  const char = getActiveCharacter();
  if (!char) return;
  const name = document.getElementById("originTraitName").value.trim();
  const desc = document.getElementById("originTraitDesc").value.trim();
  if (!name || !desc) {
    const lang = localStorage.getItem("dnd55_language") || "es";
    alert(lang === "en" ? "Please fill in all fields." : "Por favor, completa todos los campos.");
    return;
  }
  char.customOriginTraits = char.customOriginTraits || [];
  char.customOriginTraits.push({ name, desc });
  saveData();
  renderActiveCharacter();
  closeAddOriginTraitModal();
}

function removeCustomOriginTrait(index) {
  const lang = localStorage.getItem("dnd55_language") || "es";
  const confirmMsg = lang === "en" ? "Are you sure you want to delete this trait?" : "¿Estás seguro de eliminar este rasgo?";
  if (confirm(confirmMsg)) {
    const char = getActiveCharacter();
    if (!char || !char.customOriginTraits) return;
    char.customOriginTraits.splice(index, 1);
    saveData();
    renderActiveCharacter();
  }
}

// --- SISTEMA DE COMBATE, ARMAS Y ARMADURAS ---
function calculateMaxHP(char) {
  if (char.autoHP === false) {
    return char.hpMax || 10;
  }
  
  const conMod = calcModifier(getEffectiveAttributes(char).con);
  
  // 1. Clase principal
  const mainLevel = char.level || 1;
  const mainHpDieSides = parseInt((char.hitDiceType || "d8").replace("d", "")) || 8;
  
  // Nivel 1: Dado máximo + Mod. CON
  let maxHP = mainHpDieSides + conMod;
  
  // Niveles superiores de clase principal: Media fija + Mod. CON por nivel
  if (mainLevel > 1) {
    const mainAverageRoll = Math.floor(mainHpDieSides / 2) + 1;
    maxHP += (mainLevel - 1) * (mainAverageRoll + conMod);
  }
  
  // 2. Multiclases
  if (char.multiclasses && char.multiclasses.length > 0) {
    char.multiclasses.forEach(mc => {
      const mcLevel = parseInt(mc.level) || 0;
      if (mcLevel > 0) {
        let mcHpDieSides = 8;
        switch (mc.class) {
          case "Bárbaro": mcHpDieSides = 12; break;
          case "Guerrero":
          case "Paladín":
          case "Explorador":
            mcHpDieSides = 10;
            break;
          case "Mago":
          case "Hechicero":
            mcHpDieSides = 6;
            break;
          default:
            mcHpDieSides = 8;
            break;
        }
        const mcAverageRoll = Math.floor(mcHpDieSides / 2) + 1;
        maxHP += mcLevel * (mcAverageRoll + conMod);
      }
    });
  }
  
  // Modificadores extra (Especie/Origen y Dotes) basados en el nivel TOTAL
  const totalLevel = getTotalLevel(char);
  if (char.race === "Enano") {
    maxHP += (1 * totalLevel);
  }
  if (char.background === "Granjero") {
    maxHP += (2 * totalLevel); // Granjero da la dote Duro (Tough)
  }
  
  // Modificadores de dotes adicionales (por si se añade la dote manualmente)
  if (char.feats && char.feats.length > 0) {
    const hasTough = char.feats.some(f => f && f.name && (f.name.includes("Duro") || f.name.includes("Tough")));
    // Si ya lo contamos por Granjero, no lo volvemos a contar
    if (hasTough && char.background !== "Granjero") {
      maxHP += (2 * totalLevel);
    }
  }
  
  return Math.max(1, maxHP);
}

function calculateAC(char) {
  if (char.activeWildShape && typeof WILD_SHAPE_BEASTS !== 'undefined' && WILD_SHAPE_BEASTS[char.activeWildShape]) {
    const beast = WILD_SHAPE_BEASTS[char.activeWildShape];
    const isMoon = char.subclass === "Luna";
    if (isMoon) {
      const wisMod = calcModifier(getEffectiveAttributes(char).wis);
      return Math.max(beast.ac, 13 + wisMod);
    }
    return beast.ac;
  }

  if (char.autoAC === false) {
    return char.ac || 10;
  }

  const dexMod = calcModifier(getEffectiveAttributes(char).dex);

  // Buscar armadura equipada
  const equippedArmor = (char.inventory || []).find(i => i.itemType === "Armadura" && i.equipped);
  
  // Buscar escudo equipado
  const equippedShield = (char.inventory || []).find(i => i.itemType === "Escudo" && i.equipped);
  const shieldBonus = equippedShield ? (equippedShield.shieldAC || 2) : 0;

  let baseAC = 10;
  let dexBonus = dexMod;

  if (equippedArmor) {
    baseAC = equippedArmor.armorAC || 10;
    const armorType = equippedArmor.armorType || "Ligera";
    
    if (armorType === "Media") {
      dexBonus = Math.min(2, dexMod);
    } else if (armorType === "Pesada") {
      dexBonus = 0;
    }
    
    // D&D 2024: Estilo de Defensa (+1 CA si viste armadura)
    const hasDefense = (char.fightingStyles || []).some(fs => fs && fs.name && (fs.name.toLowerCase().includes("defensa") || fs.name.toLowerCase().includes("defense")));
    if (hasDefense) {
      baseAC += 1;
    }
  } else {
    // Defensa sin armadura
    if (char.class === "Bárbaro") {
      const conMod = calcModifier(getEffectiveAttributes(char).con);
      baseAC = 10 + conMod;
    } else if (char.class === "Monje") {
      if (!equippedShield) {
        const wisMod = calcModifier(getEffectiveAttributes(char).wis);
        baseAC = 10 + wisMod;
      }
    }
  }

  return baseAC + dexBonus + shieldBonus;
}

function formatWeaponProps(props, unit) {
  const lang = localStorage.getItem("dnd55_language") || "es";
  if (!props) return lang === "en" ? "None" : "Ninguna";
  
  let formatted = props;
  
  if (unit === "metros") {
    formatted = formatted.replace(/(\d+)\/(\d+)/g, (match, p1, p2) => {
      const m1 = Math.round(parseFloat(p1) * 0.3 * 10) / 10;
      const m2 = Math.round(parseFloat(p2) * 0.3 * 10) / 10;
      return `${m1}/${m2} m`;
    });
    formatted = formatted.replace(/(\d+)\s*pies/gi, (match, p1) => {
      const m = Math.round(parseFloat(p1) * 0.3 * 10) / 10;
      return `${m} m`;
    });
  } else if (unit === "casillas") {
    formatted = formatted.replace(/(\d+)\/(\d+)/g, (match, p1, p2) => {
      const c1 = Math.round(parseFloat(p1) / 5);
      const c2 = Math.round(parseFloat(p2) / 5);
      return `${c1}/${c2} c.`;
    });
    formatted = formatted.replace(/(\d+)\s*pies/gi, (match, p1) => {
      const c = Math.round(parseFloat(p1) / 5);
      return `${c} c.`;
    });
    return formatted;
  }
  return props;
}

