// --- LANZADOR DE DADOS RÁPIDO ---
let activeQuickDieSides = 20;

function openQuickDiceModal() {
  const modal = document.getElementById("quickDiceModal");
  if (!modal) return;
  modal.classList.add("active");
  
  // Reiniciar valores por defecto
  document.getElementById("quickDiceQty").value = 1;
  document.getElementById("quickDiceMod").value = 0;
  
  // Resetear radios de ventaja
  const radios = document.getElementsByName("quickDiceAdv");
  radios.forEach(r => {
    r.checked = r.value === "normal";
  });
  
  // Activar d20 por defecto
  selectQuickDie(20);
}

function closeQuickDiceModal() {
  const modal = document.getElementById("quickDiceModal");
  if (modal) {
    modal.classList.remove("active");
  }
}

function selectQuickDie(sides) {
  activeQuickDieSides = sides;
  
  // Actualizar estado activo en botones
  const boxes = document.querySelectorAll(".quick-dice-box");
  boxes.forEach(box => {
    const s = parseInt(box.getAttribute("data-sides"));
    if (s === sides) {
      box.classList.add("active");
    } else {
      box.classList.remove("active");
    }
  });
  
  // Mostrar/ocultar sección de ventaja (solo para d20)
  const advSection = document.getElementById("quickDiceAdvSection");
  if (advSection) {
    advSection.style.display = sides === 20 ? "block" : "none";
  }
}

function rollQuickDice() {
  const qty = Math.max(1, parseInt(document.getElementById("quickDiceQty").value) || 1);
  const mod = parseInt(document.getElementById("quickDiceMod").value) || 0;
  const sides = activeQuickDieSides;
  
  // Leer ventaja
  let advType = "normal";
  const radios = document.getElementsByName("quickDiceAdv");
  radios.forEach(r => {
    if (r.checked) advType = r.value;
  });
  
  closeQuickDiceModal();
  
  const rolls = [];
  let total = 0;
  let mathStr = "";
  let description = "";
  let type = "normal";
  let faceValue = 0;
  
  // Idioma activo
  const lang = localStorage.getItem("dnd55_language") || "es";
  const isEn = lang === "en";
  
  if (sides === 20 && qty === 1 && (advType === "advantage" || advType === "disadvantage")) {
    // Tirada de d20 con ventaja o desventaja
    const roll1 = Math.floor(Math.random() * 20) + 1;
    const roll2 = Math.floor(Math.random() * 20) + 1;
    let chosenRoll = roll1;
    
    if (advType === "advantage") {
      chosenRoll = Math.max(roll1, roll2);
      faceValue = chosenRoll;
      total = chosenRoll + mod;
      mathStr = `d20 [${roll1}, ${roll2}] (Ventaja) ${mod >= 0 ? '+' : ''}${mod}`;
      description = isEn ? `Advantage: chose ${chosenRoll}` : `Ventaja: elegido ${chosenRoll}`;
    } else {
      chosenRoll = Math.min(roll1, roll2);
      faceValue = chosenRoll;
      total = chosenRoll + mod;
      mathStr = `d20 [${roll1}, ${roll2}] (Desventaja) ${mod >= 0 ? '+' : ''}${mod}`;
      description = isEn ? `Disadvantage: chose ${chosenRoll}` : `Desventaja: elegido ${chosenRoll}`;
    }
    
    if (chosenRoll === 20) {
      type = "critical";
      description += " - ¡CRÍTICO! 🎯";
    } else if (chosenRoll === 1) {
      type = "fumble";
      description += " - ¡PIFIA! 💀";
    }
  } else {
    // Tirada normal de cualquier dado / cantidad
    for (let i = 0; i < qty; i++) {
      rolls.push(Math.floor(Math.random() * sides) + 1);
    }
    const sum = rolls.reduce((a, b) => a + b, 0);
    total = sum + mod;
    
    const rollsStr = rolls.join(", ");
    mathStr = `${qty}d${sides} (${rollsStr}) ${mod >= 0 ? '+' : ''}${mod}`;
    faceValue = qty === 1 ? rolls[0] : total;
    
    if (sides === 20 && qty === 1) {
      if (rolls[0] === 20) {
        type = "critical";
        description = isEn ? "CRITICAL! 🎯" : "¡CRÍTICO! 🎯";
      } else if (rolls[0] === 1) {
        type = "fumble";
        description = isEn ? "FUMBLE! 💀" : "¡PIFIA! 💀";
      }
    } else {
      description = isEn ? "Quick Dice Roll" : "Tirada de dados rápida";
    }
  }
  
  const titleStr = isEn ? "Quick Roll" : "Tirada Rápida";
  showDiceRollResult(titleStr, mathStr, total, description, type, faceValue);
}

// --- IMPRESIÓN Y EXPORTACIÓN A PDF (ESTILO JUGADOR D&D) ---

function getClassSavingThrowProficiencies(className) {
  const cls = (className || "").trim().toLowerCase();
  switch (cls) {
    case "bárbaro":
    case "barbarian":
    case "guerrero":
    case "fighter":
      return ["str", "con"];
    case "bardo":
    case "bard":
      return ["dex", "cha"];
    case "clérigo":
    case "cleric":
    case "paladín":
    case "paladin":
    case "brujo":
    case "warlock":
      return ["wis", "cha"];
    case "druida":
    case "druid":
    case "mago":
    case "wizard":
      return ["int", "wis"];
    case "pícaro":
    case "rogue":
    case "picaro":
      return ["dex", "int"];
    case "explorador":
    case "ranger":
    case "monje":
    case "monk":
      return ["str", "dex"];
    case "hechicero":
    case "sorcerer":
      return ["con", "cha"];
    default:
      return [];
  }
}

function getClassSpellcastingAbility(className) {
  const cls = (className || "").trim().toLowerCase();
  switch (cls) {
    case "mago":
    case "wizard":
      return { attr: "int", name: "Inteligencia", nameEn: "Intelligence" };
    case "clérigo":
    case "cleric":
    case "druida":
    case "druid":
    case "explorador":
    case "ranger":
      return { attr: "wis", name: "Sabiduría", nameEn: "Wisdom" };
    case "bardo":
    case "bard":
    case "hechicero":
    case "sorcerer":
    case "brujo":
    case "warlock":
    case "paladín":
    case "paladin":
      return { attr: "cha", name: "Carisma", nameEn: "Charisma" };
    case "pícaro":
    case "rogue":
    case "picaro":
    case "guerrero":
    case "fighter":
      return { attr: "int", name: "Inteligencia", nameEn: "Intelligence" };
    default:
      return null;
  }
}

function buildCharacterPrintHTML(char) {
  const lang = localStorage.getItem("dnd55_language") || "es";
  const isEn = lang === "en";
  const eff = getEffectiveAttributes(char);
  const profSaves = getClassSavingThrowProficiencies(char.class);
  const prof = char.profBonus || 2;
  const bgText = char.background || (isEn ? "No Background" : "Sin Trasfondo");

  // Construir clase y nivel desglosado para multiclase
  let classLevelStr = `${char.class}${char.subclass ? ' (' + char.subclass + ')' : ''} ${char.level}`;
  if (char.multiclasses && char.multiclasses.length > 0) {
    char.multiclasses.forEach(mc => {
      classLevelStr += ` / ${mc.class}${mc.subclass ? ' (' + mc.subclass + ')' : ''} ${mc.level}`;
    });
  }

  // Construir dados de golpe desglosados para multiclase
  const classesList = window.getAllClasses ? window.getAllClasses(char) : [{class: char.class, subclass: char.subclass, level: char.level}];
  let hitDiceStr = "";
  classesList.forEach((cls, idx) => {
    let die = "d8";
    switch (cls.class) {
      case "Bárbaro":
      case "Barbarian":
        die = "d12"; break;
      case "Guerrero":
      case "Fighter":
      case "Paladín":
      case "Paladin":
      case "Explorador":
      case "Ranger":
        die = "d10"; break;
      case "Mago":
      case "Wizard":
      case "Hechicero":
      case "Sorcerer":
        die = "d6"; break;
      default:
        die = "d8"; break;
    }
    if (idx > 0) hitDiceStr += " + ";
    hitDiceStr += `${cls.level}${die}`;
  });
  const LOGO_DATA = "data:image/jpeg;base64,";

  // Inventory mapping - 2 column layout
  const otherItems = (char.inventory || []).filter(i => i.itemType !== "Arma" || !i.equipped);
  let inventoryItemsHTML = "";
  otherItems.forEach(item => {
    inventoryItemsHTML += `<div class="epic-inv-item">• ${item.name}${item.qty > 1 ? ' (x'+item.qty+')' : ''}</div>`;
  });
  // Add empty slots to fill space cleanly and allow manual writing
  const emptySlotsNeeded = Math.max(0, 16 - otherItems.length);
  for (let i = 0; i < emptySlotsNeeded; i++) {
    inventoryItemsHTML += `<div class="epic-inv-item epic-inv-empty"></div>`;
  }

  // Features list
  let featuresHtml = "";
  const speciesData = SPECIES_DB[char.race];
  if (speciesData) {
    (speciesData.traits || []).forEach(t => { featuresHtml += `<div class="epic-line"><strong>${t.name}:</strong> ${t.desc}</div>`; });
    if (char.subrace && speciesData.lineages && speciesData.lineages[char.subrace]) {
      speciesData.lineages[char.subrace].forEach(t => { featuresHtml += `<div class="epic-line"><strong>${t.name}:</strong> ${t.desc}</div>`; });
    }
  }
  const bgData = BACKGROUNDS_DB[char.background];
  if (bgData) { featuresHtml += `<div class="epic-line"><strong>${bgData.feat}:</strong> ${bgData.featDesc}</div>`; }
  
    const classes = window.getAllClasses ? window.getAllClasses(char) : [{class: char.class, subclass: char.subclass, level: char.level}];
    if (window.SUBCLASS_TRAITS_DB) {
      classes.forEach(cls => {
        if (cls.subclass && window.SUBCLASS_TRAITS_DB[cls.subclass]) {
          const traitsForLvl = window.SUBCLASS_TRAITS_DB[cls.subclass].filter(t => t.level <= (parseInt(cls.level)||1));
          traitsForLvl.forEach(t => {
            featuresHtml += `<div class="epic-line"><strong>${t.name} (${cls.subclass}):</strong> ${t.desc}</div>`;
          });
        }
      });
    }


  // Actions / Attacks list
  let extraHtml = "";
  (char.customOriginTraits || []).forEach(t => { if (t && t.name) extraHtml += `<div class="epic-line"><strong>${t.name}:</strong> ${t.desc || ""}</div>`; });
  (char.feats || []).forEach(t => { if (t && t.name) extraHtml += `<div class="epic-line"><strong>${t.name}:</strong> ${t.desc || ""}</div>`; });
  (char.fightingStyles || []).forEach(fs => { if (fs && fs.name) extraHtml += `<div class="epic-line"><strong>${fs.name}:</strong> ${fs.desc || ""}</div>`; });
  (char.invocations || []).forEach(inv => { if (inv && inv.name) extraHtml += `<div class="epic-line"><strong>${inv.name}:</strong> ${inv.desc || ""}</div>`; });
  (char.metamagic || []).forEach(mm => { if (mm && mm.name) extraHtml += `<div class="epic-line"><strong>${mm.name}:</strong> ${mm.desc || ""}</div>`; });
  (char.weaponMasteries || []).forEach(wm => { if (wm && wm.name) extraHtml += `<div class="epic-line"><strong>${wm.name}:</strong> ${wm.desc || ""}</div>`; });
  
  const equippedWeapons = (char.inventory || []).filter(i => i.itemType === "Arma" && i.equipped);
  equippedWeapons.forEach(wp => {
    let attrMod = 0;
    if (wp.weaponAttr === "Destreza") { attrMod = calcModifier(eff.dex); }
    else if (wp.weaponAttr === "Sutil") { attrMod = Math.max(calcModifier(eff.str), calcModifier(eff.dex)); }
    else if (wp.weaponAttr === "Carisma") { attrMod = calcModifier(eff.cha); }
    else { attrMod = calcModifier(eff.str); }
    const hasArchery = (char.fightingStyles || []).some(fs => fs && fs.name && (fs.name.toLowerCase().includes("arquería") || fs.name.toLowerCase().includes("archery")));
    const isRanged = wp.weaponProps && wp.weaponProps.toLowerCase().includes("distancia");
    const archeryBonus = (hasArchery && isRanged) ? 2 : 0;
    const hasDueling = (char.fightingStyles || []).some(fs => fs && fs.name && (fs.name.toLowerCase().includes("duelo") || fs.name.toLowerCase().includes("dueling")));
    const isMelee = !wp.weaponProps || (!wp.weaponProps.toLowerCase().includes("distancia") && !wp.weaponProps.toLowerCase().includes("arrojadiza"));
    const isTwoHanded = wp.weaponProps && (wp.weaponProps.toLowerCase().includes("dos manos") || wp.weaponProps.toLowerCase().includes("dos-manos"));
    const duelingBonus = (hasDueling && isMelee && !isTwoHanded) ? 2 : 0;
    const magic = wp.magicBonus || 0;
    const totalToHit = attrMod + prof + magic + archeryBonus;
    const hitSign = totalToHit >= 0 ? '+' + totalToHit : '' + totalToHit;
    const totalDmgBonus = attrMod + magic + duelingBonus;
    const dmgBonusStr = totalDmgBonus > 0 ? '+' + totalDmgBonus : (totalDmgBonus < 0 ? '' + totalDmgBonus : '');
    const dmgText = wp.weaponDamage + (dmgBonusStr ? ' ' + dmgBonusStr : '') + ' ' + (wp.weaponDamageType || '');
    extraHtml += `<div class="epic-line"><strong>${wp.name}:</strong> ${hitSign} hit. Dmg: ${dmgText}</div>`;
  });

  const attrKeys = ['str', 'dex', 'con', 'int', 'wis', 'cha'];
  const attrShort = isEn
    ? { str: 'STR', dex: 'DEX', con: 'CON', int: 'INT', wis: 'WIS', cha: 'CHA' }
    : { str: 'FUE', dex: 'DES', con: 'CON', int: 'INT', wis: 'SAB', cha: 'CAR' };
  const attrLong = isEn
    ? { str: 'STRENGTH', dex: 'DEXTERITY', con: 'CONSTITUTION', int: 'INTELLIGENCE', wis: 'WISDOM', cha: 'CHARISMA' }
    : { str: 'FUERZA', dex: 'DESTREZA', con: 'CONSTITUCIÓN', int: 'INTELIGENCIA', wis: 'SABIDURÍA', cha: 'CARISMA' };

  let attributesHTML = "";
  attrKeys.forEach(attr => {
    const score = eff[attr] || 10;
    const mod = calcModifier(score);
    const modSign = mod >= 0 ? '+' + mod : '' + mod;
    attributesHTML += `
      <div class="epic-attr-card">
        <div class="epic-attr-badge">${attrShort[attr]}</div>
        <div class="epic-attr-info">
          <span class="epic-attr-label">${attrLong[attr]}</span>
          <span class="epic-attr-score">${score}</span>
        </div>
        <div class="epic-attr-mod">${modSign}</div>
      </div>
    `;
  });

  let skillsHTML = "";
  Object.keys(DND_SKILLS).forEach(skillKey => {
    const skillDef = DND_SKILLS[skillKey];
    const skillName = isEn ? skillDef.en : skillDef.es;
    const isProf = char.skills && char.skills[skillKey]?.proficient ? true : false;
    const isExp = char.skills && char.skills[skillKey]?.expertise ? true : false;
    const mod = calculateSkillModifier(skillKey, char);
    const sign = mod >= 0 ? '+' + mod : '' + mod;
    const dotClass = isExp ? ' epic-expert' : (isProf ? ' epic-filled' : '');
    skillsHTML += `
      <div class="epic-list-row">
        <span class="epic-dot${dotClass}"></span>
        <span class="epic-list-attr">${attrShort[skillDef.attr]}</span>
        <span class="epic-list-name">${skillName}</span>
        <span class="epic-list-mod">${sign}</span>
      </div>
    `;
  });

  let savesHTML = "";
  attrKeys.forEach(attr => {
    const isProf = profSaves.includes(attr);
    const mod = calcModifier(eff[attr] || 10);
    const finalMod = mod + (isProf ? prof : 0);
    const sign = finalMod >= 0 ? '+' + finalMod : '' + finalMod;
    savesHTML += `
      <div class="epic-list-row">
        <span class="epic-dot${isProf ? ' epic-filled' : ''}"></span>
        <span class="epic-list-attr">${attrShort[attr]}</span>
        <span class="epic-list-name">${attrLong[attr]}</span>
        <span class="epic-list-mod">${sign}</span>
      </div>
    `;
  });

  let html = `
<div class="epic-sheet">
  
  <!-- === HEADER === -->
  <div class="epic-header">
    <div class="epic-logo-area">
      <div class="epic-seal-frame">
        <img src="${LOGO_DATA}" class="epic-logo-img">
      </div>
    </div>
    
    <div class="epic-info-area">
      <div class="epic-char-name">${char.name}</div>
      <div class="epic-meta-grid">
        <div class="epic-meta-item">
          <span class="epic-meta-lbl">${isEn ? 'CLASS & LEVEL' : 'CLASE Y NIVEL'}</span>
          <span class="epic-meta-val">${classLevelStr}</span>
        </div>
        <div class="epic-meta-item">
          <span class="epic-meta-lbl">${isEn ? 'BACKGROUND' : 'ANTECEDENTE'}</span>
          <span class="epic-meta-val">${bgText}</span>
        </div>
        <div class="epic-meta-item">
          <span class="epic-meta-lbl">${isEn ? 'RACE' : 'RAZA'}</span>
          <span class="epic-meta-val">${char.race}${char.subrace ? ' ('+char.subrace+')' : ''}</span>
        </div>
      </div>
    </div>

    <div class="epic-status-summary">
      <div class="epic-insp-box">
        <span class="epic-small-lbl">${isEn ? 'INSPIRATION' : 'INSPIRACIÓN'}</span>
        <div class="epic-circle-slot"></div>
      </div>
      <div class="epic-prof-box">
        <span class="epic-small-lbl">${isEn ? 'PROF. BONUS' : 'BONIF. COMP.'}</span>
        <div class="epic-shield-slot">+${prof}</div>
      </div>
    </div>
  </div>

  <!-- === MAIN BODY === -->
  <div class="epic-main-grid">
    
    <!-- COLUMN 1: Attributes & Proficiencies -->
    <div class="epic-col1">
      <div class="epic-section-header">${isEn ? 'ATTRIBUTES' : 'ATRIBUTOS'}</div>
      <div class="epic-attrs-column">
        ${attributesHTML}
      </div>

      <div class="epic-box epic-prof-card">
        <div class="epic-card-title">${isEn ? 'PROFICIENCIES & LANGUAGES' : 'COMPETENCIAS Y IDIOMAS'}</div>
        <div class="epic-prof-line"><strong>${isEn ? 'ARMOR' : 'ARMADURAS'}:</strong> ${(char.armorProficiencies || []).join(', ') || '-'}</div>
        <div class="epic-prof-line"><strong>${isEn ? 'WEAPONS' : 'ARMAS'}:</strong> ${(char.weaponProficiencies || []).join(', ') || '-'}</div>
        <div class="epic-prof-line"><strong>${isEn ? 'TOOLS' : 'HERRAMIENTAS'}:</strong> ${(char.toolProficiencies || []).join(', ') || '-'}</div>
        <div class="epic-prof-line"><strong>${isEn ? 'LANGUAGES' : 'IDIOMAS'}:</strong> ${(char.languages || []).join(', ') || '-'}</div>
      </div>
    </div>

    <!-- COLUMN 2: Combat & Skills -->
    <div class="epic-col2">
      <!-- Combat Shapes Row -->
      <div class="epic-shapes-row">
        <div class="epic-shape-box">
          <div class="epic-shape-shield">${char.ac}</div>
          <span class="epic-shape-lbl">${isEn ? 'ARMOR' : 'C.A.'}</span>
        </div>
        <div class="epic-shape-box">
          <div class="epic-shape-circle"></div>
          <span class="epic-shape-lbl">${isEn ? 'INIT' : 'INIC.'}</span>
        </div>
        <div class="epic-shape-box">
          <div class="epic-shape-hex">${char.speed}</div>
          <span class="epic-shape-lbl">${isEn ? 'SPEED' : 'VEL.'}</span>
        </div>
        <div class="epic-shape-box">
          <div class="epic-shape-heart"><span class="epic-heart-sub">MAX</span>${char.hpMax}</div>
          <span class="epic-shape-lbl">${isEn ? 'HP' : 'P.V.'}</span>
        </div>
        <div class="epic-shape-box">
          <div class="epic-shape-temp-hp">${char.tempHP || ''}</div>
          <span class="epic-shape-lbl">${isEn ? 'TEMP HP' : 'PV TEMP.'}</span>
        </div>
        <div class="epic-hd-box">
          <span class="epic-shape-lbl">${isEn ? 'HIT DICE' : 'DADOS GOLPE'}</span>
          <div class="epic-hd-val">${char.level}${char.hitDiceType || 'd8'}</div>
        </div>
      </div>

      <!-- Saves Block -->
      <div class="epic-box epic-saves-card">
        <div class="epic-card-title">${isEn ? 'SAVING THROWS' : 'TIRADAS DE SALVACIÓN'}</div>
        <div class="epic-list-container">
          ${savesHTML}
        </div>
      </div>

      <!-- Skills Block -->
      <div class="epic-box epic-skills-card">
        <div class="epic-card-title">${isEn ? 'SKILLS' : 'HABILIDADES'}</div>
        <div class="epic-list-container">
          ${skillsHTML}
        </div>
      </div>
    </div>

    <!-- COLUMN 3: Features & Actions -->
    <div class="epic-col3">
      <!-- Features & Traits -->
      <div class="epic-box epic-features-card">
        <div class="epic-card-title">${isEn ? 'FEATURES & TRAITS' : 'RASGOS Y ATRIBUTOS'}</div>
        <div class="epic-scroll-area">
          ${featuresHtml || '<div class="epic-line-empty"></div><div class="epic-line-empty"></div>'}
        </div>
      </div>

      <!-- Actions & Attacks -->
      <div class="epic-box epic-actions-card">
        <div class="epic-card-title">${isEn ? 'ACTIONS & ATTACKS' : 'ACCIONES Y ATAQUES'}</div>
        <div class="epic-scroll-area">
          ${extraHtml || '<div class="epic-line-empty"></div><div class="epic-line-empty"></div>'}
        </div>
      </div>

      <!-- Core Beliefs (Personality Grid) -->
      <div class="epic-box epic-beliefs-card">
        <div class="epic-card-title">${isEn ? 'CORE BELIEFS & TRAITS' : 'CREENCIAS Y PERSONALIDAD'}</div>
        <div class="epic-beliefs-grid">
          <div class="epic-belief-item">
            <span class="epic-belief-lbl">${isEn ? 'PERSONALITY' : 'RASGOS PERSONALIDAD'}</span>
            <div class="epic-belief-line"></div>
          </div>
          <div class="epic-belief-item">
            <span class="epic-belief-lbl">${isEn ? 'IDEALS' : 'IDEALES'}</span>
            <div class="epic-belief-line"></div>
          </div>
          <div class="epic-belief-item">
            <span class="epic-belief-lbl">${isEn ? 'BONDS' : 'LAZOS'}</span>
            <div class="epic-belief-line"></div>
          </div>
          <div class="epic-belief-item">
            <span class="epic-belief-lbl">${isEn ? 'FLAWS' : 'DEFECTOS'}</span>
            <div class="epic-belief-line"></div>
          </div>
        </div>
      </div>
    </div>

  </div>

  <!-- === BOTTOM ROW === -->
  <div class="epic-bottom-row">
    <!-- Equipment (2 cols) -->
    <div class="epic-box epic-equipment-card">
      <div class="epic-card-title">${isEn ? 'EQUIPMENT & INVENTORY' : 'EQUIPO E INVENTARIO'}</div>
      <div class="epic-inventory-grid">
        ${inventoryItemsHTML}
      </div>
    </div>

    <!-- Coins -->
    <div class="epic-box epic-coins-card">
      <div class="epic-card-title">${isEn ? 'COINS' : 'MONEDAS'}</div>
      <div class="epic-coin-grid">
        <div class="epic-coin-row"><span class="epic-coin-lbl">PO</span><div class="epic-coin-val"></div></div>
        <div class="epic-coin-row"><span class="epic-coin-lbl">PP</span><div class="epic-coin-val"></div></div>
        <div class="epic-coin-row"><span class="epic-coin-lbl">PE</span><div class="epic-coin-val"></div></div>
        <div class="epic-coin-row"><span class="epic-coin-lbl">PC</span><div class="epic-coin-val"></div></div>
      </div>
    </div>

    <!-- Notes -->
    <div class="epic-box epic-notes-card">
      <div class="epic-card-title">${isEn ? 'NOTAS & LEDGER' : 'NOTAS Y BITÁCORA'}</div>
      <div class="epic-notes-area">
        <div class="epic-notes-line"></div>
        <div class="epic-notes-line"></div>
        <div class="epic-notes-line"></div>
        <div class="epic-notes-line"></div>
      </div>
    </div>
  </div>

</div>
  `;

  // === APPEND DRUID WILD SHAPE PAGE ===
  const isDruid = char.class === "Druida" || char.class === "Druid";
  if (isDruid) {
    const lvl = char.level || 1;
    const isMoon = char.subclass === "Luna";
    
    // Determinar límites de CR y habilidades (nadar/volar) según nivel
    let maxCR = 0.25;
    let allowSwim = false;
    let allowFly = false;

    if (isMoon) {
      if (lvl >= 8) {
        allowSwim = true;
        allowFly = true;
      } else if (lvl >= 6) {
        allowSwim = true;
      }
      
      if (lvl >= 18) maxCR = 6.0;
      else if (lvl >= 15) maxCR = 5.0;
      else if (lvl >= 12) maxCR = 4.0;
      else if (lvl >= 9) maxCR = 3.0;
      else if (lvl >= 6) maxCR = 2.0;
      else maxCR = 1.0;
    } else {
      if (lvl >= 8) {
        maxCR = 1.0;
        allowSwim = true;
        allowFly = true;
      } else if (lvl >= 4) {
        maxCR = 0.5;
        allowSwim = true;
      } else {
        maxCR = 0.25;
      }
    }

    let beastsHTML = "";
    Object.keys(WILD_SHAPE_BEASTS).forEach(beastKey => {
      const beast = WILD_SHAPE_BEASTS[beastKey];
      
      // Validar filtros
      if (beast.cr > maxCR) return;
      if (beast.swim > 0 && !allowSwim) return;
      if (beast.fly > 0 && !allowFly) return;

      // Acciones de la bestia
      let beastActionsHTML = "";
      (beast.actions || []).forEach(act => {
        const hitSign = act.toHit > 0 ? "+" + act.toHit : (act.toHit === 0 ? "" : act.toHit);
        beastActionsHTML += `
          <div class="epic-beast-action">
            <strong>${lang === "en" ? act.nameEn : act.name}:</strong> 
            ${act.toHit !== 0 ? `<span>${hitSign} hit.</span>` : ''} 
            ${act.damage !== "-" ? `<span>Dmg: ${act.damage} (${lang === "en" ? act.typeEn : act.type}).</span>` : ''} 
            <span style="color:#444;">${lang === "en" ? act.descEn : act.desc}</span>
          </div>
        `;
      });

      beastsHTML += `
        <div class="epic-beast-card">
          <h3 class="epic-beast-name">${lang === "en" ? beast.nameEn : beast.name} <span class="epic-beast-cr">[VD ${beast.cr}]</span></h3>
          <div class="epic-beast-stats">
            <strong>FUE:</strong> ${beast.str} | <strong>DES:</strong> ${beast.dex} | <strong>CON:</strong> ${beast.con} | <strong>CA:</strong> ${beast.ac}
          </div>
          <div class="epic-beast-speeds">
            <strong>Vel:</strong> ${beast.speed}p ${beast.swim ? `| <strong>Nadar:</strong> ${beast.swim}p` : ''} ${beast.fly ? `| <strong>Volar:</strong> ${beast.fly}p` : ''}
          </div>
          <div class="epic-beast-senses">
            <strong>Sentidos:</strong> ${lang === "en" ? beast.sensesEn : beast.senses}
          </div>
          <div class="epic-beast-actions-list">
            ${beastActionsHTML}
          </div>
        </div>
      `;
    });

    html += `
<div class="epic-sheet page-break-before">
  
  <!-- === HEADER === -->
  <div class="epic-header">
    <div class="epic-logo-area">
      <div class="epic-seal-frame">
        <img src="${LOGO_DATA}" class="epic-logo-img">
      </div>
    </div>
    
    <div class="epic-info-area">
      <div class="epic-char-name">${isEn ? 'Wild Shapes Ledger' : 'Registro de Formas Salvajes'}</div>
      <div class="epic-meta-grid" style="grid-template-columns: 1fr 1fr 1fr;">
        <div class="epic-meta-item">
          <span class="epic-meta-lbl">${isEn ? 'CHARACTER' : 'PERSONAJE'}</span>
          <span class="epic-meta-val">${char.name}</span>
        </div>
        <div class="epic-meta-item">
          <span class="epic-meta-lbl">${isEn ? 'LEVEL' : 'NIVEL DRUIDA'}</span>
          <span class="epic-meta-val">${char.level} (${char.subclass || 'Sin Círculo'})</span>
        </div>
        <div class="epic-meta-item">
          <span class="epic-meta-lbl">${isEn ? 'MAX CHALLENGE' : 'VD MÁXIMA'}</span>
          <span class="epic-meta-val">VD ${maxCR} ${allowSwim ? ' Nadar' : ''}${allowFly ? ' Volar' : ''}</span>
        </div>
      </div>
    </div>
  </div>

  <!-- === BEASTS LIST === -->
  <div class="epic-beasts-columns">
    ${beastsHTML || '<p style="text-align:center;font-style:italic;">No hay formas disponibles en este nivel.</p>'}
  </div>

</div>
`;
  }

  return html;
}
function buildSpellPrintHTML(char) {
  const lang = localStorage.getItem("dnd55_language") || "es";
  const isEn = lang === "en";

  // Construir clase y nivel desglosado para multiclase
  let classLevelStr = `${char.class}${char.subclass ? ' (' + char.subclass + ')' : ''} ${char.level}`;
  if (char.multiclasses && char.multiclasses.length > 0) {
    char.multiclasses.forEach(mc => {
      classLevelStr += ` / ${mc.class}${mc.subclass ? ' (' + mc.subclass + ')' : ''} ${mc.level}`;
    });
  }

  const mySpellIds = char.spells || [];
  const mySpells = SPELLS_DB.filter(s => mySpellIds.includes(s.id));

  const spellcasting = getClassSpellcastingAbility(char.class);
  let spellcastingHeaderHTML = "";

  if (spellcasting) {
    const eff = getEffectiveAttributes(char);
    const mod = calcModifier(eff[spellcasting.attr] || 10);
    const prof = char.profBonus || 2;
    const saveDC = 8 + prof + mod;
    const attackBonus = mod + prof;
    const attackBonusSign = attackBonus >= 0 ? "+" + attackBonus : attackBonus;
    const abilityName = isEn ? spellcasting.nameEn : spellcasting.name;

    spellcastingHeaderHTML = `
      <div class="epic-status-summary" style="height: 100%;">
        <div class="epic-prof-box" style="width:75px;">
          <span class="epic-small-lbl">${isEn ? 'ABILITY' : 'APTITUD'}</span>
          <div class="epic-circle-slot" style="font-family:'Cinzel',serif;font-size:9pt;font-weight:bold;display:flex;align-items:center;justify-content:center;background:#fff;width:25px;height:25px;border:1.5px solid #704c1e;border-radius:50%;box-shadow:0 0 0 1px #fff inset, 0 0 0 1.5px #704c1e inset;">${abilityName}</div>
        </div>
        <div class="epic-prof-box" style="width:70px;">
          <span class="epic-small-lbl">${isEn ? 'SAVE DC' : 'CD SALV.'}</span>
          <div class="epic-circle-slot" style="font-family:'Cinzel',serif;font-size:11pt;font-weight:bold;display:flex;align-items:center;justify-content:center;background:#fff;width:25px;height:25px;border:1.5px solid #704c1e;border-radius:50%;box-shadow:0 0 0 1px #fff inset, 0 0 0 1.5px #704c1e inset;">${saveDC}</div>
        </div>
        <div class="epic-prof-box" style="width:70px;">
          <span class="epic-small-lbl">${isEn ? 'SPELL ATK' : 'ATK CONJ.'}</span>
          <div class="epic-shield-slot" style="width:32px;height:32px;background:url('data:image/svg+xml;utf8,<svg viewBox=\'0 0 100 100\' xmlns=\'http://www.w3.org/2000/svg\'><path d=\'M50 10 L90 20 L90 60 Q90 90 50 100 Q10 90 10 60 L10 20 Z\' fill=\'white\' stroke=\'%23704c1e\' stroke-width=\'4\'/></svg>') no-repeat center;background-size:contain;display:flex;align-items:center;justify-content:center;font-size:9pt;font-weight:bold;font-family:'Cinzel',serif;padding-top:4px;box-sizing:border-box;">${attackBonusSign}</div>
        </div>
      </div>
    `;
  }

  const LOGO_DATA = "data:image/jpeg;base64,";

  let html = `
<div class="epic-sheet">
  
  <!-- === HEADER === -->
  <div class="epic-header">
    <div class="epic-logo-area">
      <div class="epic-seal-frame">
        <img src="${LOGO_DATA}" class="epic-logo-img">
      </div>
    </div>
    
    <div class="epic-info-area">
      <div class="epic-char-name">${isEn ? 'Spellbook' : 'Libro de Hechizos'}</div>
      <div class="epic-meta-grid" style="grid-template-columns: 1fr 1fr;">
        <div class="epic-meta-item">
          <span class="epic-meta-lbl">${isEn ? 'CHARACTER' : 'PERSONAJE'}</span>
          <span class="epic-meta-val">${char.name}</span>
        </div>
        <div class="epic-meta-item">
          <span class="epic-meta-lbl">${isEn ? 'CLASS & LEVEL' : 'CLASE Y NIVEL'}</span>
          <span class="epic-meta-val">${classLevelStr}</span>
        </div>
      </div>
    </div>

    ${spellcastingHeaderHTML}
  </div>

  <!-- === SPELLBOOK COLUMNS === -->
  <div class="epic-spellbook-columns">
`;

  if (mySpells.length === 0) {
    html += `<p style="grid-column: 1 / -1; text-align:center; color:#704c1e; font-style:italic; font-family:'Georgia', serif; font-size:10pt; margin-top:20px;">${isEn ? 'No spells prepared.' : 'No tienes hechizos preparados en tu ficha.'}</p>`;
  } else {
    const spellsByLevel = {};
    for (let i = 0; i <= 9; i++) spellsByLevel[i] = [];

    mySpells.forEach(s => {
      spellsByLevel[s.level].push(s);
    });

    for (let i = 0; i <= 9; i++) {
      if (spellsByLevel[i].length > 0) {
        spellsByLevel[i].sort((a, b) => a.name.localeCompare(b.name));
        
        let levelName = "";
        if (i === 0) {
          levelName = isEn ? "Cantrips" : "Trucos (Nivel 0)";
        } else {
          levelName = isEn ? `Level ${i}` : `Nivel ${i}`;
        }

        html += `
          <div class="epic-spell-group">
            <h2 class="epic-spell-group-title">${levelName}</h2>
        `;

        spellsByLevel[i].forEach(spell => {
          let componentsText = "";
          if (spell.components) {
            const hasV = spell.components.v ? "V" : "";
            const hasS = spell.components.s ? "S" : "";
            const hasM = spell.components.m ? "M" : "";
            componentsText = [hasV, hasS, hasM].filter(Boolean).join(", ");
            if (spell.components.m_desc) componentsText += " (" + spell.components.m_desc + ")";
          }

          const rangeText = spell.range || "Personal";
          const timeText = spell.time || "1 acción";
          const schoolText = spell.school || "Evocación";

          html += `
            <div class="epic-spell-card-compact">
              <h3 class="epic-spell-name-compact">${spell.name} <span class="epic-spell-school-compact">[${schoolText}]</span></h3>
              <div class="epic-spell-meta-compact">
                <strong>${isEn ? 'Time' : 'Tpo'}:</strong> ${timeText} | 
                <strong>${isEn ? 'Rng' : 'Alc'}:</strong> ${rangeText} | 
                <strong>${isEn ? 'Cmp' : 'Cmp'}:</strong> ${componentsText} | 
                <strong>${isEn ? 'Dur' : 'Dur'}:</strong> ${spell.duration || 'Instantánea'}
              </div>
              <div class="epic-spell-desc-compact">${spell.description}</div>
            </div>
          `;
        });

        html += `
          </div>
        `;
      }
    }
  }

  html += `
  </div>
</div>
`;

  return html;
}
function printCharacterSheet() {
  const char = getActiveCharacter();
  if (!char) return;

  const printArea = document.getElementById("printArea");
  if (!printArea) return;

  // Cargar contenido imprimible de la ficha
  printArea.innerHTML = buildCharacterPrintHTML(char);

  // Cerrar el modal de ajustes
  closeGlobalSettingsModal();

  // Esperar a que se renderice y disparar diálogo de impresión
  setTimeout(() => {
    if (window.AndroidPrinter && typeof window.AndroidPrinter.print === 'function') {
      window.AndroidPrinter.print();
    } else {
      window.print();
      // Limpiar después de que el cuadro de impresión haya cerrado
      setTimeout(() => {
        printArea.innerHTML = "";
      }, 2000);
    }
  }, 800);
}

function printSpellSheet() {
  const char = getActiveCharacter();
  if (!char) return;

  const printArea = document.getElementById("printArea");
  if (!printArea) return;

  // Cargar contenido del libro de conjuros
  printArea.innerHTML = buildSpellPrintHTML(char);

  // Cerrar el modal de ajustes
  closeGlobalSettingsModal();

  // Esperar a que se renderice y disparar diálogo de impresión
  setTimeout(() => {
    if (window.AndroidPrinter && typeof window.AndroidPrinter.print === 'function') {
      window.AndroidPrinter.print();
    } else {
      window.print();
      // Limpiar después de que el cuadro de impresión haya cerrado
      setTimeout(() => {
        printArea.innerHTML = "";
      }, 2000);
    }
  }, 800);
}

// --- PANTALLA DE SELECCIÓN DE PERSONAJES ---
function showCharacterSelectionScreen() {
  const emptyState = document.getElementById('emptyAppState');
  if (emptyState) emptyState.style.display = 'none';
  const charState = document.getElementById('characterSelectionState');
  if (charState) charState.style.display = 'flex';
  renderCharacterSelectionScreen();
}

function selectCharacterFromScreen(id) {
  activeCharId = id;
  saveData();
  const charState = document.getElementById('characterSelectionState');
  if (charState) charState.style.display = 'none';
  renderActiveCharacter();
  switchTab('ficha');
}

function renderCharacterSelectionScreen() {
  const grid = document.getElementById('characterSelectionGrid');
  if (!grid) return;
  grid.innerHTML = '';
  characters.forEach(char => {
    const level = char.level || 1;
    const cls = char.class || 'Sin clase';
    const species = char.race || 'Sin raza';
    
    const card = document.createElement('div');
    card.className = 'hero-card';
    card.onclick = () => selectCharacterFromScreen(char.id);
    
    const avatar = document.createElement('div');
    avatar.className = 'hero-card-avatar';
    avatar.textContent = char.name ? char.name.charAt(0).toUpperCase() : '?';
    
    const nameDiv = document.createElement('div');
    nameDiv.className = 'hero-card-name';
    nameDiv.textContent = char.name || 'Héroe sin nombre';
    
    const descDiv = document.createElement('div');
    descDiv.className = 'hero-card-desc';
    descDiv.textContent = 'Nivel ' + level + ' • ' + species + ' ' + cls;
    
    const delBtn = document.createElement('div');
    delBtn.className = 'hero-card-delete';
    delBtn.innerHTML = '🗑️';
    delBtn.title = 'Eliminar personaje';
    delBtn.onclick = (e) => {
      e.stopPropagation();
      deleteCharacterFromScreen(char.id);
    };
    
    card.appendChild(delBtn);
    card.appendChild(avatar);
    card.appendChild(nameDiv);
    card.appendChild(descDiv);
    
    grid.appendChild(card);
  });
}

function deleteCharacterFromScreen(id) {
  const lang = localStorage.getItem("dnd55_language") || "es";
  if (confirm(lang === "en" ? "Are you sure you want to delete this character?" : "¿Estás seguro de que quieres eliminar este personaje?")) {
    characters = characters.filter(c => c.id !== id);
    if (activeCharId === id) {
      activeCharId = characters.length > 0 ? characters[0].id : null;
    }
    saveData();
    renderCharacterList();
    if (characters.length > 0) {
      renderCharacterSelectionScreen();
    } else {
      document.getElementById('characterSelectionState').style.display = 'none';
      renderActiveCharacter(); // This will show the empty state
    }
  }
}
